                normR = clamp(normR, 0.0, 1.0);

                // Temperature gradient (hotter inside, cooler outside)
                float temperature = 1.0 - normR * 0.6;

                // Base disk color (orange-yellow to white gradient)
                vec3 diskColor = mix(
                    vec3(1.0, 0.5, 0.2),  // Outer edge (cooler, orange)
                    vec3(1.0, 0.9, 0.7),  // Inner edge (hotter, white-yellow)
