                float spiralNoise = noise(vec2(r * 0.5, angle * 3.0 + r * 0.3));
                brightness *= 0.7 + 0.3 * spiralNoise;

                // Doppler effect: left side (approaching) brighter, right side (receding) darker
                // Tangential velocity direction at this point
                vec3 tangentDir = normalize(vec3(-pos.z, 0.0, pos.x));
                float doppler = dot(tangentDir, normalize(dir));
                float dopplerFactor = 1.0 + uDopplerStrength * doppler;
                brightness *= dopplerFactor;

                // Edge softening
                float edgeFade = smoothstep(uDiskInner, uDiskInner + 0.5, r) * 
                                 smoothstep(uDiskOuter, uDiskOuter - 1.0, r);

                return diskColor * brightness * edgeFade;
            }

            // Gravitational bending force (simplified geodesic)
            vec3 bendGravity(vec3 pos, vec3 dir, float r) {
                // Force toward center, stronger closer to black hole
                float force = 1.0 / (r * r + 0.1);
                vec3 forceDir = -normalize(pos);

                // Bend the ray direction toward the black hole
                dir += forceDir * force * uStepScale * 0.5;
                return normalize(dir);
            }

            void main() {
                // Normalize UV to -1 to 1
                vec2 uv = vUv * 2.0 - 1.0;

                // Aspect ratio calculation with zero protection
                float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
                uv.x *= aspect;

                // Build camera coordinate system
                vec3 camDir = normalize(iCameraDir);
                vec3 camRight = normalize(cross(camDir, iCameraUp));
                vec3 camUp = cross(camRight, camDir);

                // Calculate ray direction from FOV
                float fovRad = iFov * PI / 180.0;
                float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);
                vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
