                // Ray marching state
                vec3 pos = rayOrigin;
                vec3 dir = rayDir;
                vec3 accumulatedColor = vec3(0.0);
                float accumulatedAlpha = 0.0;

                bool hitDisk = false;
                bool absorbed = false;

