                    float stepSize;
                    if (r < uDiskOuter + 2.0 && r > uDiskInner - 2.0) {
                        stepSize = max(uMinStep, r * uStepScale * 0.5);
                    } else {
                        stepSize = max(uMinStep, r * uStepScale);
