                                diskCol += vec3(glow * 0.5, glow * 0.3, glow * 0.1);

                                float diskAlpha = 0.8;
                                accumulatedColor += diskCol * (1.0 - accumulatedAlpha);
                                accumulatedAlpha += diskAlpha * (1.0 - accumulatedAlpha);
                                hitDisk = true;
                            }
                        }
                    }

                    // === Photon ring glow (gravitational lensing effect) ===
                    // Add glow when ray passes close to the photon sphere (~1.5 * Schwarzschild radius)
                    float photonSphereR = uBhRadius * 1.5;
                    float distToPhotonSphere = abs(r - photonSphereR);
                    if (distToPhotonSphere < 1.0) {
                        float ringGlow = uGlowIntensity * exp(-distToPhotonSphere * 3.0);
                        accumulatedColor += vec3(ringGlow, ringGlow * 0.7, ringGlow * 0.4) * (1.0 - accumulatedAlpha);
                    }

