                    // Add subtle glow that increases closer to the black hole
                    float generalGlow = 0.005 / (pow(r, 2.0) + 0.1);
                    accumulatedColor += vec3(generalGlow) * (1.0 - accumulatedAlpha);

                    // Apply gravitational bending to ray direction
                    dir = bendGravity(pos, dir, r);

                    // March forward
                    pos += dir * stepSize;
                }

                // === Final color composition ===
                vec3 finalColor;

                if (absorbed) {
                    // Ray was absorbed by black hole
                    // Still show accumulated glow (photon ring, etc.)
                    finalColor = accumulatedColor;
                    // Add subtle dark center with edge glow
                    finalColor = max(finalColor, vec3(0.02));
                } else {
                    // Ray escaped - add starfield background
                    vec3 starColor = getStarfield(dir, iTime);
                    finalColor = accumulatedColor + starColor * (1.0 - accumulatedAlpha);
                }

                // Apply exposure/tone mapping
                finalColor *= uExposure;

                // Simple tone mapping (Reinhard)
                finalColor = finalColor / (finalColor + vec3(1.0));

                // Gamma correction
                finalColor = pow(finalColor, vec3(1.0 / 2.2));

                gl_FragColor = vec4(finalColor, 1.0);
            }
        `;

        // =====================================================
        // THREE.JS SETUP
        // =====================================================

        // Scene
        const scene = new THREE.Scene();

        // Camera
        const camera = new THREE.PerspectiveCamera(
            60,
            window.innerWidth / window.innerHeight,
            0.1,
            1000
        );
        camera.position.set(0, 5, CONFIG.cameraDistance);
        camera.lookAt(0, 0, 0);

        // Renderer
        const renderer = new THREE.WebGLRenderer({ 
            antialias: true,
            powerPreference: 'high-performance'
        });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

        // Important: Append canvas to body (not just a div)
        document.body.appendChild(renderer.domElement);

        // OrbitControls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.minDistance = CONFIG.minZoom;
        controls.maxDistance = CONFIG.maxZoom;
        controls.enablePan = true;
        controls.mouseButtons = {
            LEFT: THREE.MOUSE.ROTATE,
            MIDDLE: THREE.MOUSE.DOLLY,
            RIGHT: THREE.MOUSE.PAN
        };

        // =====================================================
        // FULL-SCREEN QUAD (Black Hole Shader)
        // =====================================================

        const blackHoleMaterial = new THREE.ShaderMaterial({
            vertexShader,
            fragmentShader,
            uniforms: {
                iResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
                iCameraPos: { value: new THREE.Vector3() },
                iCameraDir: { value: new THREE.Vector3() },
                iCameraUp: { value: new THREE.Vector3() },
                iFov: { value: camera.fov },
                iTime: { value: 0.0 },

                // Black hole parameters
                uBhRadius: { value: CONFIG.bhRadius },
                uDiskInner: { value: CONFIG.diskInner },
                uDiskOuter: { value: CONFIG.diskOuter },
                uStepScale: { value: CONFIG.stepScale },
                uMinStep: { value: CONFIG.minStep },
                uDiskBrightness: { value: CONFIG.diskBrightness },
                uGlowIntensity: { value: CONFIG.glowIntensity },
                uDopplerStrength: { value: CONFIG.dopplerStrength },
                uStarDensity: { value: CONFIG.starDensity },
                uStarTwinkleSpeed: { value: CONFIG.starTwinkleSpeed },
                uExposure: { value: CONFIG.exposure }
            }
        });

        // Create full-screen quad
        const quadGeometry = new THREE.PlaneGeometry(2, 2);
        const quadMesh = new THREE.Mesh(quadGeometry, blackHoleMaterial);
        quadMesh.frustumCulled = false;  // Critical: prevent frustum culling
        scene.add(quadMesh);  // Add to scene, NOT to camera

        // =====================================================
        // ANIMATION LOOP
        // =====================================================

        let shaderTime = 0.0;
        const clock = new THREE.Clock();
        const tempVec = new THREE.Vector3();
        const resVec = new THREE.Vector2();

        // Animation toggle
        const animToggle = document.getElementById('anim-toggle');
        const animStatus = document.getElementById('anim-status');

        animToggle.addEventListener('change', () => {
            animStatus.textContent = animToggle.checked ? 'ON' : 'OFF';
        });

        function animate() {
            requestAnimationFrame(animate);

            const delta = clock.getDelta();

            // Update time based on toggle state
            if (animToggle.checked) {
                shaderTime += delta;
            }

            // Update uniforms every frame (CRITICAL for correct rendering)
            blackHoleMaterial.uniforms.iTime.value = shaderTime;

            // Get rendering buffer size with zero protection
            renderer.getDrawingBufferSize(resVec);
            blackHoleMaterial.uniforms.iResolution.value.set(
                Math.max(resVec.x, 1),
                Math.max(resVec.y, 1)
            );

            // Update camera uniforms
            blackHoleMaterial.uniforms.iCameraPos.value.copy(camera.position);

            // Get camera forward direction using getWorldDirection
            camera.getWorldDirection(tempVec);
            blackHoleMaterial.uniforms.iCameraDir.value.copy(tempVec);

            blackHoleMaterial.uniforms.iCameraUp.value.copy(camera.up);
            blackHoleMaterial.uniforms.iFov.value = camera.fov;

            // Update controls
            controls.update();

            // Render
            renderer.render(scene, camera);
        }

        // =====================================================
        // WINDOW RESIZE HANDLER
        // =====================================================

        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        // Start animation
        animate();

        console.log('GARGANTUA Black Hole Visualization initialized');
        console.log('Controls: Left-click rotate, Right-click pan, Scroll zoom');
        console.log('Toggle animation with the switch in the bottom-left card');
    </script>
